};

export function useCanvasBoard() {
  const [rawNodes, setNodes, onNodesChange] = useNodesState<CanvasNodeData>(initialNodes);
  const [edges, setEdges, onEdgesChange] = useEdgesState<CanvasEdge>(initialEdges);
  const { screenToFlowPosition } = useReactFlow();
  const spawnCountRef = useRef(0);
  const objectUrlsRef = useRef<string[]>([]);

  useEffect(() => {
    const objectUrls = objectUrlsRef.current;

    return () => {
      objectUrls.forEach((url) => URL.revokeObjectURL(url));
    };
  }, []);

  const updateNodeData = useCallback(
    (nodeId: string, patch: Partial<CanvasNodeData>) => {
      setNodes((currentNodes) =>
        currentNodes.map((node) =>
          node.id === nodeId
            ? {
                ...node,
                data: {
                  ...node.data,
                  ...patch,
                },
              }
            : node,
        ),
      );
    },
    [setNodes],
  );

  const nodes = useMemo(
    () =>
      rawNodes.map((node) => ({
        ...node,
        data: {
          ...node.data,
          onUpdate: (patch: Partial<CanvasNodeData>) => updateNodeData(node.id, patch),
        },
      })),
    [rawNodes, updateNodeData],
  );

  const getSpawnPosition = useCallback(
    (offsetX = 0, offsetY = 0) => {
      const step = spawnCountRef.current;
      const position = screenToFlowPosition({
        x: window.innerWidth / 2 + offsetX + (step % 3) * 44,
        y: window.innerHeight / 2 + offsetY + (step % 2) * 36,
      });

      spawnCountRef.current += 1;
      return position;
    },
    [screenToFlowPosition],
  );

  const addNode = useCallback(
    (node: CanvasNode) => {
      setNodes((currentNodes) => [...currentNodes, node]);
    },
    [setNodes],
  );

  const addQuickNote = useCallback(() => {
    const id = `note-${Date.now()}`;
    addNode(createQuickNoteNode(id, getSpawnPosition(-220, -60), spawnCountRef.current + 1));
  }, [addNode, getSpawnPosition]);

  const addOwnContent = useCallback(
    (files: File[]) => {
      const nextNodes = files.map((file, index) => {
        const type = inferMediaType(file);
        const previewUrl =
          type === 'image' || type === 'video' ? URL.createObjectURL(file) : undefined;

        if (previewUrl) {
          objectUrlsRef.current.push(previewUrl);
        }

        const item: CanvasAssetItem = {
          id: `${file.name}-${index}-${Date.now()}`,
          label: file.name,
          type,
          meta:
            type === 'document'
              ? `${Math.max(1, Math.round(file.size / 1024))} KB document`
              : `${Math.max(1, Math.round(file.size / 1024 / 1024))} MB ${type}`,
          previewUrl,
        };

        return createUploadedAssetNode(
          `asset-${Date.now()}-${index}`,
          getSpawnPosition(-160 + index * 48, 40 + index * 24),
          item,
        );
      });

      setNodes((currentNodes) => [...currentNodes, ...nextNodes]);
    },
    [getSpawnPosition, setNodes],
  );

  const addGeneratedContent = useCallback(
    (input: GenerateInput) => {
      const id = `generation-${Date.now()}`;
      addNode(createGenerationNode(id, getSpawnPosition(120, -20), input));
    },
    [addNode, getSpawnPosition],
  );

  const addResearchPack = useCallback(
    (input: TavilyInput) => {
      const noteId = `research-${Date.now()}`;
      const noteNode = createResearchNoteNode(noteId, getSpawnPosition(-160, 0), input);

      if (!input.includeImages) {
        addNode(noteNode);
        return;
      }

      const stackId = `${noteId}-images`;
      const stackNode = createImageStackNode(stackId, getSpawnPosition(180, 60), input.query);

      setNodes((currentNodes) => [...currentNodes, noteNode, stackNode]);
      setEdges((currentEdges) => [
        ...currentEdges,
        {
          id: `edge-${noteId}-${stackId}`,
          source: noteId,
          target: stackId,
          ...edgeDefaults,
        },
      ]);
    },
    [addNode, getSpawnPosition, setEdges, setNodes],
  );

  const addTemplate = useCallback(
    (input: TemplateInput) => {
      const id = `template-${Date.now()}`;
      addNode(createTemplateNode(id, getSpawnPosition(220, 80), input));
    },
    [addNode, getSpawnPosition],
  );

  const onConnect = useCallback(
    (connection: Connection) => {
      setEdges((currentEdges) =>
        addEdge(
          {
            ...connection,
            ...edgeDefaults,
          },
          currentEdges,
        ),
      );
    },
    [setEdges],
  );

  const actions = useMemo(
    () => ({
      addQuickNote,
      addOwnContent,
      addGeneratedContent,
      addResearchPack,
      addTemplate,
      updateNodeData,
    }),
    [addGeneratedContent, addOwnContent, addQuickNote, addResearchPack, addTemplate, updateNodeData],
  );

  return {
    nodes,
    edges,
    onNodesChange,
    onEdgesChange,
    onConnect,
    actions,
  };
}

