+async function uploadRemoteAssetToGemini(asset: CanvasAssetItem) {
+  const apiKey = getGeminiApiKey();
+  const assetUrl = getAssetUrl(asset);
+  const fileBytesResponse = await fetch(assetUrl);
+
+  if (!fileBytesResponse.ok) {
+    throw new Error(`Failed to fetch asset for context extraction: ${fileBytesResponse.status}`);
+  }
+
+  const bytes = Buffer.from(await fileBytesResponse.arrayBuffer());
+  const response = await fetch(`${GEMINI_API_BASE}/files?key=${apiKey}`, {
+    method: 'POST',
+    headers: {
+      'X-Goog-Upload-Protocol': 'raw',
