import 'server-only';

import type { ExtractedContextArtifact } from './types';
import type { WorkspaceContextPack } from './workspace-context';

const SOURCE_PRIORITY = [
  'document',
  'choice-config',
  'note',
  'template',
  'research',
  'image',
  'video',
] as const;

function sortByPriority(artifacts: ExtractedContextArtifact[]) {
  return [...artifacts].sort((a, b) => {
    const aIndex = SOURCE_PRIORITY.indexOf(a.sourceType);
    const bIndex = SOURCE_PRIORITY.indexOf(b.sourceType);
    return aIndex - bIndex;
  });
}

function dedupe(items: string[]) {
  const seen = new Set<string>();
  const result: string[] = [];

  for (const item of items) {
    const normalized = item.trim().toLowerCase();
    if (!normalized || seen.has(normalized)) {
      continue;
    }
    seen.add(normalized);
    result.push(item.trim());
  }

  return result;
}

function rankByFrequency(items: string[]) {
  const counts = new Map<string, { value: string; count: number }>();

  for (const item of items.map((entry) => entry.trim()).filter(Boolean)) {
    const key = item.toLowerCase();
    const current = counts.get(key);
    counts.set(key, {
      value: current?.value ?? item,
      count: (current?.count ?? 0) + 1,
    });
  }

  return [...counts.values()]
    .sort((a, b) => b.count - a.count || a.value.localeCompare(b.value))
    .map((entry) => entry.value);
}

export function mergeContextArtifacts(input: {
  workspaceId: string;
  sourceFingerprint: string;
  artifacts: ExtractedContextArtifact[];
}): WorkspaceContextPack {
  const artifacts = sortByPriority(input.artifacts);
  const documentArtifacts = artifacts.filter((item) => item.sourceType === 'document');
  const choiceConfigArtifacts = artifacts.filter((item) => item.sourceType === 'choice-config');
  const noteArtifacts = artifacts.filter((item) => item.sourceType === 'note');
  const templateArtifacts = artifacts.filter((item) => item.sourceType === 'template');
  const researchArtifacts = artifacts.filter((item) => item.sourceType === 'research');
  const imageArtifacts = artifacts.filter((item) => item.sourceType === 'image');
  const videoArtifacts = artifacts.filter((item) => item.sourceType === 'video');

  const allKeyFacts = dedupe(artifacts.flatMap((item) => item.keyFacts));
  const styleSignals = rankByFrequency(
    templateArtifacts.flatMap((item) => item.styleSignals).concat(
      imageArtifacts.flatMap((item) => item.styleSignals),
      videoArtifacts.flatMap((item) => item.styleSignals),
    ),
  );
  const audienceHints = dedupe(artifacts.flatMap((item) => item.audienceHints));
  const constraints = dedupe(
    documentArtifacts
      .flatMap((item) => item.constraints)
      .concat(
        noteArtifacts.flatMap((item) => item.constraints),
        choiceConfigArtifacts.flatMap((item) => item.constraints),
      ),
  );
  const claims = dedupe(
    documentArtifacts.flatMap((item) => item.claims).concat(
      artifacts.filter((item) => item.sourceType !== 'document').flatMap((item) => item.claims),
    ),
  );
  const ctas = dedupe(artifacts.flatMap((item) => item.ctas));
  const productEntities = dedupe(artifacts.flatMap((item) => item.productEntities));
  const hooks = dedupe(
    noteArtifacts.flatMap((item) => item.keyFacts).concat(
      templateArtifacts.flatMap((item) => item.keyFacts),
      researchArtifacts.flatMap((item) => item.keyFacts),
    ),
  );

  const selectedTemplates = dedupe(
    choiceConfigArtifacts.flatMap((item) => {
      const platforms = (item.rawMetadata?.platforms as Array<{ templates?: string[] }> | undefined) ?? [];
      return platforms.flatMap((platform) => platform.templates ?? []);
    }),
  );

  const platforms = dedupe(
    choiceConfigArtifacts.flatMap((item) => {
      const platformMetadata =
        (item.rawMetadata?.platforms as Array<{ platform?: string }> | undefined) ?? [];
      return platformMetadata.map((platform) => platform.platform ?? '').filter(Boolean);
    }),
  );

  const requestedContentTypes = dedupe(
    choiceConfigArtifacts.flatMap((item) => {
      const platformMetadata =
        (item.rawMetadata?.platforms as Array<{ contentTypes?: string[] }> | undefined) ?? [];
      return platformMetadata.flatMap((platform) => platform.contentTypes ?? []);
    }),
  );

  const brandSummary = dedupe(documentArtifacts.map((item) => item.summary)).join(' ');

  return {
    workspaceId: input.workspaceId,
    generatedAt: new Date().toISOString(),
    sourceFingerprint: input.sourceFingerprint,
    sources: {
      total: artifacts.length,
      notes: noteArtifacts.length,
      images: imageArtifacts.length,
      videos: videoArtifacts.length,
      documents: documentArtifacts.length,
      templates: templateArtifacts.length,
      researchItems: researchArtifacts.length,
      choiceConfigs: choiceConfigArtifacts.length,
    },
    platforms,
    requestedContentTypes,
    selectedTemplates,
    brandContext: {
      summary: brandSummary,
      productEntities,
      claims,
      constraints,
    },
    creativeDirection: {
      styleSignals,
      audienceHints,
      ctas,
      hooks,
    },
    sourceArtifacts: artifacts,
    mergedContext: {
      keyFacts: allKeyFacts,
      styleSignals,
      audienceHints,
      constraints,
      claims,
      ctas,
      productEntities,
    },
  };
}

